TELEGRAM_TOOL = {
    "type": "function",
    "function": {
        "name": "send_telegram_message",
        "description": "Envia uma mensagem para o Telegram do usuário.",
        "parameters": {
            "type": "object",
            "properties": {
                "message": {"type": "string", "description": "Texto a enviar"}
