    var json = extrairJson(texto);

    if (json && json.type === 'questions' && Array.isArray(json.questions)) {
      var antes = texto.substring(0, texto.indexOf('{')).trim();
      var html = '';
      if (antes) html += '<p>' + formatarTexto(antes) + '</p>';
